class Solution {

    public static boolean canConstruct(String ransomNote, String magazine) {
        int i = 0, j = 0;
        while (j < magazine.length()) {
            // System.out.println("i val"+i+" j val"+j);
            if (ransomNote.charAt(i) == magazine.charAt(j)) {
                // System.out.println("here");
                // System.out.println(magazine);
                magazine = magazine.substring(0, j) + magazine.substring(j + 1, magazine.length());
                j = 0;
                if(i!=ransomNote.length()-1) i++;
                else return true;
                // System.out.println(magazine);
            } else if (j < magazine.length()) {
                // System.out.println("else if");
                j++;
            } else {
                // System.out.println("Else");
                return false;
            }
        }
        // if (i == ransomNote.length()) {
        //     return true;
        // }
        return false;
    }

    public static void main(String[] args) {

        String ransomNote = "aa", magazine = "abab";
        // String ransomNote = "ab", magazine = "ab";
        // String ransomNote = "aa", magazine = "ab";
        // String ransomNote = "a", magazine = "b";

        System.out.println(canConstruct(ransomNote, magazine));

    }
}
